+/// Verify QE Identity JSON signature using the provided certificate chain
+fn verify_qe_identity_signature(
+    qe_identity: &str,
+    signature: &[u8],
+    issuer_chain: &[u8],
+) -> Result<(), Error> {
+    let certs = crypto::parse_cert_chain(issuer_chain)?;
+    if certs.is_empty() {
+        return Err(Error::InvalidCertificateChain);
+    }
+    
+    // Verify signature using leaf certificate
+    crypto::verify_signature(qe_identity.as_bytes(), signature, &certs[0])
+}
+
+/// Verify QE Report MRSIGNER, ISVPRODID, and ISVSVN against QE Identity policy
+fn verify_qe_report_against_identity(
+    qe_report: &QeReport,
+    qe_identity_json: &str,
+) -> Result<(), Error> {
+    let qe_identity: QeIdentity = serde_json::from_str(qe_identity_json)
+        .map_err(|e| Error::InvalidQeIdentity(format!("Failed to parse QE Identity: {}", e)))?;
+    
+    let identity = &qe_identity.enclave_identity;
+    
+    // Verify MRSIGNER matches expected value
+    if qe_report.mrsigner != identity.mrsigner {
+        return Err(Error::QeIdentityMismatch("MRSIGNER does not match QE Identity".into()));
+    }
+    
+    // Verify ISVPRODID matches expected value
+    if qe_report.isv_prod_id != identity.isvprodid {
+        return Err(Error::QeIdentityMismatch("ISVPRODID does not match QE Identity".into()));
+    }
+    
+    // Verify ISVSVN is greater than or equal to minimum required version
+    if qe_report.isv_svn < identity.isvsvn {
+        return Err(Error::QeIdentityMismatch(format!("ISVSVN {} is below minimum required {}", 
+            qe_report.isv_svn, identity.isvsvn)));
+    }
+    
+    Ok(())
+}
